"""`AGENTS.md` generation and update."""

from __future__ import annotations

from pathlib import Path

AGENTS_MD_TEMPLATE = """# AGENTS.md — AI Agent Instructions for {project_name}

> **Required first read:** `docs/AIprojectcontext/ai-index.md`
> **Primary context source:** `docs/AIprojectcontext/`
> **Generated by:** `aictx`

## Rules for all agents

1. Read `docs/AIprojectcontext/ai-index.md` first.
2. Do **not** read large human-facing public docs for general project context.
3. Public docs may be read only when the task is documentation-related or `aictx verify --strict` reports a public-docs impact.
4. Run `aictx verify --strict` before any public commit.
5. If context is stale, run `aictx run --project . --mode setup-context --scope full --write apply` to regenerate the full context scaffold.
   - Use `--scope changed` for targeted local refresh after tracked source changes.
6. If public docs are impacted, run `aictx public-docs update --project . --scope changed --write patch`.
   - Current behavior creates deterministic review artifacts; edit public docs manually from source facts.
7. Do not fabricate facts. Mark missing information `unknown` or `needs-source`.
8. Preserve source references for all important claims.

## Accuracy rules

- Source-trace all critical claims.
- No unsupported assumptions.
- Mark uncertainty explicitly.
- Fail closed: report `unknown` rather than guess.
"""

MANAGED_SECTION_HEADINGS = {"Rules for all agents", "Accuracy rules"}


def generate_agents_md(project_name: str, existing_content: str | None = None) -> str:
    """Return the generated AGENTS.md content."""
    generated = AGENTS_MD_TEMPLATE.format(project_name=project_name).rstrip()
    custom_sections = _extract_custom_sections(existing_content)
    if custom_sections:
        return f"{generated}\n\n{custom_sections}\n"
    return f"{generated}\n"


def write_agents_md(repo_root: Path, project_name: str) -> Path:
    """Write AGENTS.md to *repo_root*."""
    path = repo_root / "AGENTS.md"
    existing_content = path.read_text(encoding="utf-8") if path.exists() else None
    path.write_text(generate_agents_md(project_name, existing_content), encoding="utf-8")
    return path


def _extract_custom_sections(existing_content: str | None) -> str:
    """Preserve user-maintained second-level sections from an existing AGENTS.md."""
    if not existing_content:
        return ""

    sections: list[str] = []
    current_heading: str | None = None
    current_lines: list[str] = []

    for line in existing_content.splitlines():
        if line.startswith("## "):
            if current_lines and current_heading not in MANAGED_SECTION_HEADINGS:
                sections.append("\n".join(current_lines).rstrip())
            current_heading = line.removeprefix("## ").strip()
            current_lines = [line]
            continue
        if current_lines:
            current_lines.append(line)

    if current_lines and current_heading not in MANAGED_SECTION_HEADINGS:
        sections.append("\n".join(current_lines).rstrip())

    return "\n\n".join(section for section in sections if section)
